/**
 * Send a notification through the appropriate adapter.
 * Falls back to in-memory storage if no adapter is registered
 * for the channel.
 *
 * Notifications for the same recipient are serialized via a per-recipient
 * queue to guarantee delivery ordering (e.g., "order placed" always
 * arrives before "payment confirmed").
 *
 * When a PreferencesService is registered, checks user preferences
 * before sending. If no userId is provided or no preferences service
 * is set, the notification is sent unconditionally (backwards-compatible).
 */
private sendNotification(
  type: NotificationType,
  payload: NotificationPayload,
  userId?: string,
): Promise<NotificationResult | undefined> {
  const recipient = payload.recipient;
  const previous = this.recipientQueues.get(recipient) ?? Promise.resolve();
  const current = previous.then(() => this.deliverNotification(type, payload, userId));
  // Store the queue chain, swallowing errors so a failed notification
  // doesn't block subsequent ones for the same recipient.
  this.recipientQueues.set(recipient, current.then(() => {}, () => {}));
  return current;
}

private async deliverNotification(
  type: NotificationType,
  payload: NotificationPayload,
  userId?: string,
): Promise<NotificationResult | undefined> {
  if (userId && this.preferencesService) {
    if (!this.preferencesService.shouldSendNotification(userId, type, payload.channel)) {
      this.logger.info(`Notification skipped for ${userId}: blocked by preferences`);
      this.historyService?.log(`skipped-${generateNotificationId()}`, type, payload, 'skipped');
      return undefined;
    }
  }

  const id = generateNotificationId();

  const notification: Notification = {
    id,
    type,
    channel: payload.channel,
    recipient: payload.recipient,
    subject: payload.subject,
    body: payload.body,
    priority: payload.priority,
    status: 'pending',
    sentAt: new Date(),
    metadata: payload.metadata,
  };

  const adapter = this.adapters.get(payload.channel);
  if (adapter) {
    try {
      const result = await adapter.send(payload);
      notification.status = result.success ? 'sent' : 'failed';
      this.notifications.push(notification);
      this.logger.info(`Notification ${id} ${notification.status} via ${payload.channel}`);
      this.historyService?.log(id, type, payload, notification.status);
      return result;
    } catch (error) {
      notification.status = 'failed';
      this.notifications.push(notification);
      this.logger.error(`Notification ${id} failed: ${error}`);
      this.historyService?.log(id, type, payload, 'failed', String(error));
      return { success: false, notificationId: id, channel: payload.channel, error: String(error) };
    }
  }

  // No adapter registered — store as sent (in-memory fallback)
  notification.status = 'sent';
  this.notifications.push(notification);
  this.logger.info(`Notification sent: ${id} to ${payload.recipient} (no adapter, in-memory)`);
  this.historyService?.log(id, type, payload, 'sent');
  return undefined;
}

